def transition(state, action):
    s = dict(state)
    cases = {cid: dict(c) for cid, c in s.get("cases", {}).items()}
    rooms = list(s.get("rooms", []))
    horizon = int(s.get("horizon", 0))
    rejected = int(s.get("rejected", 0))

    name = action.get("name")
    params = action.get("params") or {}

    def booked_intervals(room, exclude=None):
        out = []
        for cid, c in cases.items():
            if cid == exclude:
                continue
            if c.get("status") == "booked" and c.get("room") == room:
                st = c.get("start")
                if st is not None:
                    out.append((st, st + int(c.get("duration", 0))))
        return out

    def fits(room, start, duration, exclude=None):
        if room not in rooms or start is None:
            return False
        if start < 0 or start + duration > horizon:
            return False
        for (a, b) in booked_intervals(room, exclude):
            if start < b and a < start + duration:   # half-open overlap
                return False
        return True

    def earliest_slot(duration, room=None, exclude=None, min_start=0):
        candidates = [room] if room is not None else rooms
        best = None
        for r in candidates:
            for st in range(max(0, min_start), horizon - duration + 1):
                if fits(r, st, duration, exclude):
                    if best is None or st < best[1]:
                        best = (r, st)
                    break   # earliest fitting start in this room
        return best

    if name == "book":
        cid = params.get("case")
        if cid is None:
            pend = [k for k in sorted(cases) if cases[k].get("status") == "pending"]
            cid = pend[0] if pend else None
        if cid in cases and cases[cid].get("status") == "pending":
            dur = int(cases[cid].get("duration", 0))
            room = params.get("room")
            start = params.get("start")
            if start is None:
                slot = earliest_slot(dur, room=room)
                if slot is not None:
                    room, start = slot
            if fits(room, start, dur):
                cases[cid]["status"] = "booked"
                cases[cid]["room"] = room
                cases[cid]["start"] = start
            else:
                rejected += 1
        else:
            rejected += 1

    elif name == "delay":
        cid = params.get("case")
        if cid is None:
            bk = [k for k in sorted(cases) if cases[k].get("status") == "booked"]
            cid = bk[0] if bk else None
        if cid in cases and cases[cid].get("status") == "booked":
            c = cases[cid]
            dur = int(c.get("duration", 0))
            room = c.get("room")
            cur = int(c.get("start", 0))
            if "start" in params and params.get("start") is not None:
                new = params.get("start")
            elif params.get("by") is not None:
                new = cur + int(params.get("by"))
            else:
                slot = earliest_slot(dur, room=room, exclude=cid, min_start=cur + 1)
                new = slot[1] if slot is not None else None
            if new is not None and new > cur and fits(room, new, dur, exclude=cid):
                c["start"] = new
            else:
                rejected += 1
        else:
            rejected += 1

    elif name == "cancel":
        cid = params.get("case")
        if cid is None:
            bk = [k for k in sorted(cases) if cases[k].get("status") == "booked"]
            cid = bk[-1] if bk else None
        if cid in cases and cases[cid].get("status") == "booked":
            cases[cid]["status"] = "pending"
            cases[cid]["room"] = None
            cases[cid]["start"] = None
        else:
            rejected += 1

    s["cases"] = cases
    s["booked"] = sum(1 for c in cases.values() if c.get("status") == "booked")
    s["pending"] = sum(1 for c in cases.values() if c.get("status") == "pending")
    s["utilization"] = sum(int(c.get("duration", 0)) for c in cases.values()
                           if c.get("status") == "booked")
    s["rejected"] = rejected
    return s

