def perceive(data):
    text = data if isinstance(data, str) else str(data)
    rooms = []
    horizon = 0
    cases = {}
    for raw in text.split("\n"):
        line = raw.strip()
        if not line or line.startswith("#"):
            continue
        low = line.lower()
        if low.startswith("rooms:"):
            rooms = [r.strip() for r in line.split(":", 1)[1].split(",") if r.strip()]
        elif low.startswith("horizon:"):
            try:
                horizon = int(line.split(":", 1)[1].strip())
            except ValueError:
                horizon = 0
        else:
            parts = line.split()
            if len(parts) >= 3:
                cid, cname, dur = parts[0], parts[1], parts[2]
            elif len(parts) == 2:
                cid, cname, dur = parts[0], parts[0], parts[1]
            else:
                continue
            try:
                duration = int(dur)
            except ValueError:
                continue
            cases[cid] = {"name": cname.replace("_", " "), "duration": duration,
                          "status": "pending", "room": None, "start": None}
    return {
        "rooms": rooms,
        "horizon": horizon,
        "cases": cases,
        "booked": 0,
        "pending": len(cases),
        "utilization": 0,
        "rejected": 0,
    }
